class Solution {
    public boolean checkRecord(String s) {
        int absences = countAbsences(s);
        int lateDays = countLateDays(s);
        return absences <= 1 && lateDays <= 3;
    }

    private int countAbsences(String s) {
        int count = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == 'A') {
                count++;
            }
        }
        return count;
    }

    private int countLateDays(String s) {
        int count = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == 'L') {
                count++;
            }
        }
        return count;
    }
}
```

